function [yPred, metrics, ruleSet] = prediction(population, dataset, cfg)
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% Bee for Mining Open Version (B4M-Open)
%
% Function    : prediction
% Description : Perform multiclass prediction using the best rules
%               generated by the B4M population.
%
% Inputs
%   population : Optimized bee population
%   dataset    : Dataset structure containing X and Y
%   cfg        : Algorithm configuration
%
% Outputs
%   yPred      : Predicted class labels
%   metrics    : Classification performance structure
%   ruleSet    : Selected classification rules
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

%% ------------------------------------------------------------------------
% Input validation
%% ------------------------------------------------------------------------

if nargin ~= 3
    error('prediction requires population, dataset, and cfg.');
end

if isempty(population)
    error('Population cannot be empty.');
end

requiredDatasetFields = {'X','Y','nSamples','nFeatures','nClasses'};

for k = 1:numel(requiredDatasetFields)
    if ~isfield(dataset, requiredDatasetFields{k})
        error('dataset.%s is missing.', requiredDatasetFields{k});
    end
end

%% ------------------------------------------------------------------------
% Number of rules selected for each class
%% ------------------------------------------------------------------------

if isfield(cfg,'nRulesPerClass')
    nRulesPerClass = cfg.nRulesPerClass;
else
    nRulesPerClass = 5;
end

nRulesPerClass = max(1, round(nRulesPerClass));

X = dataset.X;
Y = dataset.Y(:);

nSamples  = dataset.nSamples;
nFeatures = dataset.nFeatures;
nClasses  = dataset.nClasses;

%% ------------------------------------------------------------------------
% Select best rules for every class
%% ------------------------------------------------------------------------

ruleSet = struct( ...
    'Class', {}, ...
    'Fitness', {}, ...
    'Quality', {}, ...
    'Support', {}, ...
    'LowerBound', {}, ...
    'UpperBound', {});

ruleCounter = 0;

for classID = 1:nClasses

    classIndex = find(arrayfun( ...
        @(bee) bee.Rule.Class == classID, population));

    if isempty(classIndex)
        warning('No rule was found for class %d.', classID);
        continue;
    end

    classFitness = arrayfun( ...
        @(idx) population(idx).Rule.Fitness, classIndex);

    [~, localOrder] = sort(classFitness, 'descend');

    numberSelected = min(nRulesPerClass, numel(classIndex));

    selectedIndex = classIndex(localOrder(1:numberSelected));

    for r = 1:numberSelected

        sourceRule = population(selectedIndex(r)).Rule;

        ruleCounter = ruleCounter + 1;

        ruleSet(ruleCounter).Class = sourceRule.Class;
        ruleSet(ruleCounter).Fitness = sourceRule.Fitness;
        ruleSet(ruleCounter).Quality = sourceRule.Quality;
        ruleSet(ruleCounter).Support = sourceRule.Support;
        ruleSet(ruleCounter).LowerBound = sourceRule.LowerBound;
        ruleSet(ruleCounter).UpperBound = sourceRule.UpperBound;

    end

end

if isempty(ruleSet)
    error('No valid classification rules were selected.');
end

%% ------------------------------------------------------------------------
% Feature range for normalized distance
%% ------------------------------------------------------------------------

featureRange = dataset.Xmax - dataset.Xmin;
featureRange(featureRange == 0) = 1;

%% ------------------------------------------------------------------------
% Predict every sample
%% ------------------------------------------------------------------------

yPred = zeros(nSamples,1);

for i = 1:nSamples

    sample = X(i,:);

    classScore = -inf(nClasses,1);
    classDistance = inf(nClasses,1);

    for r = 1:numel(ruleSet)

        classID = ruleSet(r).Class;

        lower = ruleSet(r).LowerBound;
        upper = ruleSet(r).UpperBound;

        isCovered = all(sample >= lower & sample <= upper);

        if isCovered

            candidateScore = ...
                ruleSet(r).Fitness + ...
                0.001 * ruleSet(r).Quality + ...
                0.0001 * ruleSet(r).Support;

            if candidateScore > classScore(classID)
                classScore(classID) = candidateScore;
            end

        else

            belowDistance = max(lower - sample, 0);
            aboveDistance = max(sample - upper, 0);

            normalizedDistance = ...
                (belowDistance + aboveDistance) ./ featureRange;

            distanceValue = mean(normalizedDistance);

            if distanceValue < classDistance(classID)
                classDistance(classID) = distanceValue;
            end

        end

    end

    %% Choose covered rule with the highest score

    if any(isfinite(classScore))

        [~, predictedClass] = max(classScore);

    else

        %% No rule covers the sample:
        %  choose the class whose rule interval is nearest

        [~, predictedClass] = min(classDistance);

        if ~isfinite(classDistance(predictedClass))
            predictedClass = mode(Y);
        end

    end

    yPred(i) = predictedClass;

end

%% ------------------------------------------------------------------------
% Build multiclass confusion matrix manually
%% ------------------------------------------------------------------------

confusionMatrix = zeros(nClasses,nClasses);

for i = 1:nSamples

    actualClass = Y(i);
    predictedClass = yPred(i);

    confusionMatrix(actualClass,predictedClass) = ...
        confusionMatrix(actualClass,predictedClass) + 1;

end

%% ------------------------------------------------------------------------
% Calculate overall accuracy
%% ------------------------------------------------------------------------

accuracy = sum(diag(confusionMatrix)) / nSamples;

%% ------------------------------------------------------------------------
% Calculate class-wise metrics
%% ------------------------------------------------------------------------

precisionPerClass = zeros(nClasses,1);
recallPerClass    = zeros(nClasses,1);
f1PerClass        = zeros(nClasses,1);

for classID = 1:nClasses

    truePositive = confusionMatrix(classID,classID);

    falsePositive = ...
        sum(confusionMatrix(:,classID)) - truePositive;

    falseNegative = ...
        sum(confusionMatrix(classID,:)) - truePositive;

    if truePositive + falsePositive > 0
        precisionPerClass(classID) = ...
            truePositive / (truePositive + falsePositive);
    else
        precisionPerClass(classID) = 0;
    end

    if truePositive + falseNegative > 0
        recallPerClass(classID) = ...
            truePositive / (truePositive + falseNegative);
    else
        recallPerClass(classID) = 0;
    end

    precisionValue = precisionPerClass(classID);
    recallValue = recallPerClass(classID);

    if precisionValue + recallValue > 0

        f1PerClass(classID) = ...
            2 * precisionValue * recallValue / ...
            (precisionValue + recallValue);

    else

        f1PerClass(classID) = 0;

    end

end

%% ------------------------------------------------------------------------
% Macro-averaged metrics
%% ------------------------------------------------------------------------

macroPrecision = mean(precisionPerClass);
macroRecall    = mean(recallPerClass);
macroF1        = mean(f1PerClass);

%% ------------------------------------------------------------------------
% Store results
%% ------------------------------------------------------------------------

metrics = struct();

metrics.Accuracy = accuracy;

metrics.Precision = macroPrecision;
metrics.Recall = macroRecall;
metrics.F1Score = macroF1;

metrics.PrecisionPerClass = precisionPerClass;
metrics.RecallPerClass = recallPerClass;
metrics.F1PerClass = f1PerClass;

metrics.ConfusionMatrix = confusionMatrix;

metrics.NumberOfRules = numel(ruleSet);

end